// ═══════════════════════════════════════════════════════════════════════════════
// AUTH SCREEN — Premium redesign
// ═══════════════════════════════════════════════════════════════════════════════
function AuthScreen({onAuth, onBack}){
  const G = useThemeColors();
  const [mode,setMode]=useState("login"); // login | signup | forgot | forgot_sent | reset
  const [tab,setTab]=useState("email");   // email | phone
  const [email,setEmail]=useState("");
  const [phone,setPhone]=useState("");
  const [password,setPassword]=useState("");
  const [name,setName]=useState("");
  const [otp,setOtp]=useState(["","","","","",""]);
  const [otpSent,setOtpSent]=useState(false);
  const [loading,setLoading]=useState(false);
  const [error,setError]=useState("");
  const [showPass,setShowPass]=useState(false);
  const [newPassword,setNewPassword]=useState("");
  const [showNewPass,setShowNewPass]=useState(false);
  const otpRefs=[useRef(),useRef(),useRef(),useRef(),useRef(),useRef()];

  // Detect password-reset redirect from email link
  useEffect(()=>{
    if(typeof window!=="undefined"&&window.location.search.includes("reset=true")){
      setMode("reset");
      // Clean up the URL
      window.history.replaceState({},"",window.location.pathname);
    }
  },[]);

  // ── EMAIL / PASSWORD AUTH ────────────────────────────────────────────────
  const handleEmail=async()=>{
    if(!email.trim()||!password.trim()){setError("Please fill in all fields.");return;}
    if(mode==="signup"&&!name.trim()){setError("Please enter your name.");return;}
    if(password.length<6){setError("Password must be at least 6 characters.");return;}
    setLoading(true);setError("");
    try{
      if(mode==="signup"){
        const{data,error:err}=await supabase.auth.signUp({
          email:email.trim(),
          password,
          options:{data:{name:name.trim()}},
        });
        if(err) throw err;
        if(data.user&&!data.session){
          setMode("email_sent");
          setLoading(false);return;
        }
        if(data.user) onAuth({id:data.user.id,email:data.user.email,name:name.trim(),provider:"email",isNew:true});
      } else {
        const{data,error:err}=await supabase.auth.signInWithPassword({email:email.trim(),password});
        if(err) throw err;
        const meta=data.user.user_metadata||{};
        onAuth({id:data.user.id,email:data.user.email,name:meta.name||email.trim().split("@")[0],provider:"email"});
      }
    }catch(e){setError(e.message||"Authentication failed.");}
    setLoading(false);
  };

  // ── PHONE / OTP AUTH ─────────────────────────────────────────────────────
  const handleSendOTP=async()=>{
    if(!phone.trim()){setError("Please enter your phone number.");return;}
    setLoading(true);setError("");
    try{
      const{error:err}=await supabase.auth.signInWithOtp({phone:phone.trim()});
      if(err) throw err;
      setOtpSent(true);
      setTimeout(()=>otpRefs[0].current?.focus(),100);
    }catch(e){setError(e.message||"Failed to send code. Check the number and try again.");}
    setLoading(false);
  };

  const handleVerifyOTP=async()=>{
    const code=otp.join("");
    if(code.length<6){setError("Please enter the 6-digit code.");return;}
    setLoading(true);setError("");
    try{
      const{data,error:err}=await supabase.auth.verifyOtp({phone:phone.trim(),token:code,type:"sms"});
      if(err) throw err;
      const u=data.user;
      onAuth({id:u.id,phone:u.phone,name:"User",provider:"phone"});
    }catch(e){setError(e.message||"Incorrect code. Try again.");}
    setLoading(false);
  };

  // ── GOOGLE OAUTH ─────────────────────────────────────────────────────────
  const handleGoogle=async()=>{
    setLoading(true);setError("");
    try{
      // Get the OAuth URL from Supabase without redirecting
      const{data,error:err}=await supabase.auth.signInWithOAuth({
        provider:"google",
        options:{
          // Use deep link scheme so Android hands control back to the app
          redirectTo: window?.Capacitor?.isNativePlatform?.()
            ? "com.destiniq.app://"
            : window.location.origin,
          queryParams:{prompt:"select_account"},
          skipBrowserRedirect:true,
        },
      });
      if(err){setError(err.message);setLoading(false);return;}
      if(data?.url){
        // Check if running in Capacitor native app
        const isNative = typeof window!=="undefined" && window?.Capacitor?.isNativePlatform?.();
        if(isNative && window?.Capacitor?.Plugins?.Browser){
          // Use in-app browser — stays inside the app, no Chrome
          // Use Capacitor Browser via global plugin — no import needed
          const CapBrowser = window?.Capacitor?.Plugins?.Browser;
          if(CapBrowser){
            await CapBrowser.open({
              url: data.url,
              presentationStyle: "popover",
              toolbarColor: "#0a0a0f",
            });
          } else {
            // Fallback — open in system browser
            window.open(data.url, "_blank");
          }
        } else {
          // Web — normal redirect
          window.location.href = data.url;
        }
      }
    }catch(e){
      setError("Sign in failed. Please try again.");
      setLoading(false);
    }
  };

  // ── FORGOT PASSWORD ────────────────────────────────────────────────────
  const handleForgot=async()=>{
    if(!email.trim()){setError("Enter your email address first.");return;}
    setLoading(true);setError("");
    try{
      const{error:err}=await supabase.auth.resetPasswordForEmail(email.trim(),{
        redirectTo:window.location.origin+"?reset=true",
      });
      if(err) throw err;
      setMode("forgot_sent");
    }catch(e){setError(e.message||"Failed to send reset email.");}
    setLoading(false);
  };

  // ── RESET PASSWORD (after redirect back) ────────────────────────────────
  const handleReset=async()=>{
    if(newPassword.length<6){setError("Password must be at least 6 characters.");return;}
    setLoading(true);setError("");
    try{
      const{error:err}=await supabase.auth.updateUser({password:newPassword});
      if(err) throw err;
      setMode("login");setError("");
      setNewPassword("");
      // Session is already active after reset — trigger onAuth
      const{data:{session}}=await supabase.auth.getSession();
      if(session?.user){
        const u=session.user;
        const meta=u.user_metadata||{};
        onAuth({id:u.id,email:u.email,name:meta.name||meta.full_name||(u.email?.split("@")[0])||"User",provider:"email"});
      }
    }catch(e){setError(e.message||"Failed to update password.");}
    setLoading(false);
  };

  const handleOTPInput=(i,val)=>{
    if(!/^\d*$/.test(val)) return;
    const next=[...otp]; next[i]=val.slice(-1);
    setOtp(next);
    if(val&&i<5) otpRefs[i+1].current?.focus();
  };

  const handleOTPKey=(i,e)=>{
    if(e.key==="Backspace"&&!otp[i]&&i>0) otpRefs[i-1].current?.focus();
  };

  const btnStyle={width:"100%",padding:"14px",borderRadius:12,border:"1px solid var(--cream-15)",background:"var(--night)",color:"var(--cream)",fontSize:14,fontWeight:600,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:10,transition:"all 0.2s",marginBottom:10};
  const inputStyle={width:"100%",background:"var(--midnight)",border:"1px solid var(--cream-15)",borderRadius:12,padding:"13px 16px",color:"var(--cream)",fontSize:14,outline:"none",boxSizing:"border-box",marginBottom:12};

  // ── FORGOT PASSWORD SCREEN ────────────────────────────────────────────────
  if(mode==="forgot"){
    return(
      <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:"20px"}}>
        <div style={{width:"100%",maxWidth:420}}>
          <div style={{textAlign:"center",marginBottom:32}}>
            <div style={{fontSize:28,fontWeight:800,color:"var(--cream)",marginBottom:8}}>Destin<b style={{color:"var(--gold)"}}>IQ</b></div>
            <div style={{fontSize:15,color:"var(--cream-60)"}}>Reset your password</div>
          </div>
          <div style={{background:"var(--night)",border:"1px solid var(--cream-10)",borderRadius:20,padding:"28px 24px"}}>
            <p style={{fontSize:13,color:"var(--cream-60)",marginBottom:16,lineHeight:1.6}}>Enter the email address on your account and we'll send you a reset link.</p>
            <input style={{width:"100%",background:"var(--midnight)",border:"1px solid var(--cream-15)",borderRadius:12,padding:"13px 16px",color:"var(--cream)",fontSize:14,outline:"none",boxSizing:"border-box",marginBottom:12}} type="email" placeholder="Email address" value={email} onChange={e=>setEmail(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handleForgot()}/>
            {error&&<div style={{background:"rgba(248,113,113,0.1)",border:"1px solid rgba(248,113,113,0.3)",borderRadius:10,padding:"10px 14px",marginBottom:12,fontSize:13,color:"#F87171"}}>{error}</div>}
            <button onClick={handleForgot} disabled={loading} style={{width:"100%",padding:"14px",borderRadius:12,border:"none",background:loading?"var(--cream-15)":"var(--gold)",color:loading?"var(--cream-40)":"#000",fontSize:15,fontWeight:700,cursor:loading?"not-allowed":"pointer",marginBottom:16}}>{loading?"Sending…":"Send reset link"}</button>
            <div style={{textAlign:"center",fontSize:13}}><span onClick={()=>{setMode("login");setError("");}} style={{color:"var(--cream-40)",cursor:"pointer",textDecoration:"underline"}}>Back to sign in</span></div>
          </div>
        </div>
      </div>
    );
  }

  if(mode==="email_sent"){
    return(
      <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:"20px"}}>
        <div style={{width:"100%",maxWidth:420,textAlign:"center"}}>
          <div style={{fontSize:28,fontWeight:800,color:"var(--cream)",marginBottom:8}}>Destin<b style={{color:"var(--gold)"}}>IQ</b></div>
          <div style={{background:"var(--night)",border:"1px solid var(--cream-10)",borderRadius:20,padding:"36px 24px",marginTop:24}}>
            <div style={{fontSize:40,marginBottom:16}}>✉️</div>
            <div style={{fontSize:18,fontWeight:700,color:"var(--cream)",marginBottom:12}}>Confirm your email</div>
            <p style={{fontSize:14,color:"var(--cream-60)",lineHeight:1.7,marginBottom:8}}>We sent a confirmation link to <b style={{color:"var(--cream)"}}>{email}</b>.</p>
            <p style={{fontSize:13,color:"var(--cream-40)",lineHeight:1.7,marginBottom:24}}>Click the link in the email to activate your account, then come back to sign in. Check your spam if you don't see it.</p>
            <button onClick={async()=>{await supabase.auth.resend({type:"signup",email:email.trim()});alert("Confirmation email resent!");}} style={{background:"none",border:"1px solid var(--cream-15)",borderRadius:10,padding:"10px 20px",color:"var(--cream-40)",fontSize:13,cursor:"pointer",marginBottom:16}}>Resend email</button>
            <br/>
            <span onClick={()=>{setMode("login");setError("");}} style={{color:"var(--gold)",cursor:"pointer",fontWeight:600,fontSize:14}}>Back to sign in</span>
          </div>
        </div>
      </div>
    );
  }

  if(mode==="forgot_sent"){
    return(
      <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:"20px"}}>
        <div style={{width:"100%",maxWidth:420,textAlign:"center"}}>
          <div style={{fontSize:28,fontWeight:800,color:"var(--cream)",marginBottom:8}}>Destin<b style={{color:"var(--gold)"}}>IQ</b></div>
          <div style={{background:"var(--night)",border:"1px solid var(--cream-10)",borderRadius:20,padding:"36px 24px",marginTop:24}}>
            <div style={{fontSize:40,marginBottom:16}}>📬</div>
            <div style={{fontSize:18,fontWeight:700,color:"var(--cream)",marginBottom:12}}>Check your inbox</div>
            <p style={{fontSize:14,color:"var(--cream-60)",lineHeight:1.7,marginBottom:24}}>We sent a password reset link to <b style={{color:"var(--cream)"}}>{email}</b>. Click the link in the email to set a new password.</p>
            <span onClick={()=>{setMode("login");setError("");}} style={{color:"var(--gold)",cursor:"pointer",fontWeight:600,fontSize:14}}>Back to sign in</span>
          </div>
        </div>
      </div>
    );
  }

  if(mode==="reset"){
    return(
      <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:"20px"}}>
        <div style={{width:"100%",maxWidth:420}}>
          <div style={{textAlign:"center",marginBottom:32}}>
            <div style={{fontSize:28,fontWeight:800,color:"var(--cream)",marginBottom:8}}>Destin<b style={{color:"var(--gold)"}}>IQ</b></div>
            <div style={{fontSize:15,color:"var(--cream-60)"}}>Set a new password</div>
          </div>
          <div style={{background:"var(--night)",border:"1px solid var(--cream-10)",borderRadius:20,padding:"28px 24px"}}>
            <div style={{position:"relative",marginBottom:12}}>
              <input style={{width:"100%",background:"var(--midnight)",border:"1px solid var(--cream-15)",borderRadius:12,padding:"13px 44px 13px 16px",color:"var(--cream)",fontSize:14,outline:"none",boxSizing:"border-box"}} type={showNewPass?"text":"password"} placeholder="New password (min 6 characters)" value={newPassword} onChange={e=>setNewPassword(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handleReset()}/>
              <button onClick={()=>setShowNewPass(p=>!p)} style={{position:"absolute",right:12,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",color:"var(--cream-30)",cursor:"pointer",fontSize:13}}>{showNewPass?"Hide":"Show"}</button>
            </div>
            {error&&<div style={{background:"rgba(248,113,113,0.1)",border:"1px solid rgba(248,113,113,0.3)",borderRadius:10,padding:"10px 14px",marginBottom:12,fontSize:13,color:"#F87171"}}>{error}</div>}
            <button onClick={handleReset} disabled={loading} style={{width:"100%",padding:"14px",borderRadius:12,border:"none",background:loading?"var(--cream-15)":"var(--gold)",color:loading?"var(--cream-40)":"#000",fontSize:15,fontWeight:700,cursor:loading?"not-allowed":"pointer"}}>{loading?"Updating…":"Update password"}</button>
          </div>
        </div>
      </div>
    );
  }


  // Apple OAuth (Supabase)
  const handleApple=async()=>{
    setLoading(true);setError("");
    try{
      const{error:err}=await supabase.auth.signInWithOAuth({
        provider:"apple",
        options:{redirectTo:typeof window!=="undefined"?window.location.origin:"/"}
      });
      if(err) setError(err.message);
    }catch(e){setError("Apple sign-in unavailable. Please try email.");}
    setLoading(false);
  };
  // Aliases — handleEmail already handles both modes
  const handleLogin=handleEmail;
  const handleSignup=handleEmail;

  const iStyle={width:"100%",padding:"14px 16px",background:G.inp,
    border:"1px solid "+G.inpBorder,borderRadius:12,color:G.cream,
    fontSize:15,outline:"none",boxSizing:"border-box",fontFamily:"inherit",
    transition:"border-color .2s",
};

  const showEmailForm = tab==="email" && (mode==="login"||mode==="signup");

  return(
    <div style={{minHeight:"100vh",background:G.bg,display:"flex",flexDirection:"column",
      alignItems:"center",justifyContent:"center",padding:"24px",
      fontFamily:"-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif",color:G.cream}}>

      {/* Back */}
      {onBack&&mode==="login"&&!showEmailForm&&(
        <button onClick={onBack}
          style={{position:"absolute",top:20,left:20,background:"none",border:"none",
            color:G.dimmer,cursor:"pointer",fontSize:22,lineHeight:1}}>←</button>
      )}

      <div style={{width:"100%",maxWidth:400}}>

        {/* ── Logo ── */}
        <div style={{textAlign:"center",marginBottom:36}}>
          <div style={{fontSize:"clamp(18px,5vw,26px)",fontWeight:800,color:G.cream,marginBottom:8,letterSpacing:"-.3px"}}>
            Destin<span style={{color:G.gold}}>IQ</span>
          </div>
          <h1 style={{fontSize:"clamp(16px,4.5vw,24px)",fontWeight:800,color:G.cream,margin:"0 0 6px",lineHeight:1.2}}>
            {mode==="forgot"||mode==="forgot_sent"?"Reset your password"
             :mode==="reset"?"Set new password"
             :"Start your transformation"}
          </h1>
          <p style={{fontSize:13,color:G.dim,margin:0}}>
            {mode==="forgot"?"We'll send you a reset link"
             :mode==="forgot_sent"?"Check your email for the link"
             :mode==="reset"?"Choose a new secure password"
             :mode==="signup"?"Create your account":"Welcome back"}
          </p>
          {(()=>{
            const p=new URLSearchParams(typeof window!=="undefined"?window.location.search:"");
            const wasOAuthErr=p.get("error_code")||p.get("error");
            return wasOAuthErr?(
              <div style={{marginTop:12,padding:"10px 14px",background:"rgba(240,180,41,0.08)",
                border:"1px solid rgba(240,180,41,0.2)",borderRadius:10,fontSize:12,
                color:"rgba(240,180,41,0.9)"}}>
                ⚠️ Sign-in session expired. Please try again.
              </div>
            ):null;
          })()}
        </div>

        {/* ── FORGOT / RESET flows ── */}
        {(mode==="forgot"||mode==="forgot_sent"||mode==="reset")&&(
          <div style={{background:G.card,border:"1px solid "+G.border,borderRadius:18,padding:"28px 24px"}}>
            {mode==="forgot_sent"?(
              <div style={{textAlign:"center",padding:"12px 0"}}>
                <div style={{fontSize:40,marginBottom:14}}>📬</div>
                <p style={{color:G.dim,fontSize:14,lineHeight:1.7,margin:"0 0 20px"}}>Check your inbox — the reset link expires in 1 hour.</p>
                <button onClick={()=>setMode("login")}
                  style={{background:G.gold,color:"#000",border:"none",borderRadius:11,
                    padding:"13px 28px",fontSize:14,fontWeight:700,cursor:"pointer",width:"100%"}}>
                  Back to Sign In
                </button>
              </div>
            ):mode==="forgot"?(
              <>
                <input type="email" value={email} onChange={e=>setEmail(e.target.value)}
                  placeholder="your@email.com" style={iStyle}
                  onFocus={e=>e.target.style.borderColor="rgba(240,180,41,0.4)"}
                  onBlur={e=>e.target.style.borderColor=G.inpBorder}/>
                {error&&<p style={{color:"#e05252",fontSize:13,margin:"10px 0 0"}}>{error}</p>}
                <button onClick={handleForgot} disabled={loading||!email.trim()}
                  style={{marginTop:16,width:"100%",padding:"14px",background:G.gold,color:"#000",
                    border:"none",borderRadius:11,fontSize:14,fontWeight:700,cursor:"pointer",
                    opacity:loading||!email.trim()?.8:1}}>
                  {loading?"Sending…":"Send Reset Link"}
                </button>
                <button onClick={()=>setMode("login")}
                  style={{marginTop:12,width:"100%",padding:"10px",background:"none",
                    color:G.dimmer,border:"none",fontSize:13,cursor:"pointer"}}>← Back to Sign In</button>
              </>
            ):(
              <>
                <div style={{position:"relative",marginBottom:12}}>
                  <input type={showPass?"text":"password"} value={newPassword}
                    onChange={e=>setNewPassword(e.target.value)} placeholder="New password (min 8 chars)"
                    style={iStyle} onFocus={e=>e.target.style.borderColor="rgba(240,180,41,0.4)"}
                    onBlur={e=>e.target.style.borderColor=G.inpBorder}/>
                  <button onClick={()=>setShowPass(p=>!p)}
                    style={{position:"absolute",right:14,top:"50%",transform:"translateY(-50%)",
                      background:"none",border:"none",color:G.dimmer,cursor:"pointer",fontSize:13}}>
                    {showPass?"Hide":"Show"}
                  </button>
                </div>
                {error&&<p style={{color:"#e05252",fontSize:13,margin:"0 0 10px"}}>{error}</p>}
                <button onClick={handleReset} disabled={loading||newPassword.length<8}
                  style={{width:"100%",padding:"14px",background:G.gold,color:"#000",
                    border:"none",borderRadius:11,fontSize:14,fontWeight:700,cursor:"pointer",
                    opacity:loading||newPassword.length<8?0.7:1}}>
                  {loading?"Updating…":"Set New Password"}
                </button>
              </>
            )}
          </div>
        )}

        {/* ── MAIN AUTH VIEW ── */}
        {(mode==="login"||mode==="signup")&&(
          <div style={{background:G.card,border:"1px solid "+G.border,borderRadius:18,padding:"28px 24px"}}>

            {/* Google */}
            <button onClick={handleGoogle} disabled={loading}
              style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"center",gap:12,
                padding:"14px",background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.1)",
                borderRadius:12,cursor:"pointer",fontFamily:"inherit",marginBottom:10,
                color:G.cream,fontSize:14,fontWeight:500,transition:"background .15s"}}
              onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.08)"}
              onMouseLeave={e=>e.currentTarget.style.background="rgba(255,255,255,0.04)"}>
              <svg width="18" height="18" viewBox="0 0 24 24">
                <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"/>
                <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
              </svg>
              Continue with Google
            </button>

            {/* Apple */}
            <button onClick={handleApple} disabled={loading}
              style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"center",gap:12,
                padding:"14px",background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.1)",
                borderRadius:12,cursor:"pointer",fontFamily:"inherit",marginBottom:10,
                color:G.cream,fontSize:14,fontWeight:500,transition:"background .15s"}}
              onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.08)"}
              onMouseLeave={e=>e.currentTarget.style.background="rgba(255,255,255,0.04)"}>
              <svg width="16" height="18" viewBox="0 0 814 1000" fill={G.cream}>
                <path d="M788.1 340.9c-5.8 4.5-108.2 62.2-108.2 190.5 0 148.4 130.3 200.9 134.2 202.2-.6 3.2-20.7 71.9-68.7 141.9-42.8 61.6-87.5 123.1-155.5 123.1s-85.5-39.5-164-39.5c-76.5 0-103.7 40.8-165.9 40.8s-105-37.5-150.9-99.2C-33.2 753.2 0 571.5 0 570c0-0.4 0-0.8 0-1.2 0.3-140.1 89.4-214.2 177.3-214.2 61.2 0 112.2 38.7 151.7 38.7 37.7 0 98.4-40.8 165.2-40.8 27.4 0 108.2 2.3 162.9 86.4zm-137.4-195.7c5.8-27.4 15.4-52.5 30.4-76.5 33-48.7 93.1-85.5 148.5-85.5 2.9 0 5.8 0 8.7 0.3-3.2 30.4-14.8 58.2-30.4 82.5-32.4 49.4-90.9 84.5-157.2 79.2z"/>
              </svg>
              Continue with Apple
            </button>

            {/* Email toggle button */}
            {!showEmailForm&&(
              <button onClick={()=>setTab("email")}
                style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"center",gap:12,
                  padding:"14px",background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.1)",
                  borderRadius:12,cursor:"pointer",fontFamily:"inherit",marginBottom:20,
                  color:G.cream,fontSize:14,fontWeight:500,transition:"background .15s"}}
                onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.08)"}
                onMouseLeave={e=>e.currentTarget.style.background="rgba(255,255,255,0.04)"}>
                <span style={{fontSize:16}}>✉️</span>
                Continue with Email
              </button>
            )}

            {/* OR divider */}
            {!showEmailForm&&(
              <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:20}}>
                <div style={{flex:1,height:1,background:"rgba(232,220,200,0.08)"}}/>
                <span style={{fontSize:11,color:G.dimmer,letterSpacing:".08em"}}>OR</span>
                <div style={{flex:1,height:1,background:"rgba(232,220,200,0.08)"}}/>
              </div>
            )}

            {/* Email form (expands when email button clicked) */}
            {showEmailForm&&(
              <>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:16}}>
                  <button onClick={()=>setTab("")}
                    style={{background:"none",border:"none",color:G.dimmer,cursor:"pointer",fontSize:18,padding:0,lineHeight:1}}>←</button>
                  <span style={{fontSize:14,fontWeight:600,color:G.cream}}>Continue with Email</span>
                </div>

                {mode==="signup"&&(
                  <input value={name} onChange={e=>setName(e.target.value)} placeholder="Your first name"
                    style={{...iStyle,marginBottom:10}}
                    onFocus={e=>e.target.style.borderColor="rgba(240,180,41,0.4)"}
                    onBlur={e=>e.target.style.borderColor=G.inpBorder}/>
                )}
                <input type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="Email address"
                  style={{...iStyle,marginBottom:10}}
                  onFocus={e=>e.target.style.borderColor="rgba(240,180,41,0.4)"}
                  onBlur={e=>e.target.style.borderColor=G.inpBorder}/>
                <div style={{position:"relative",marginBottom:8}}>
                  <input type={showPass?"text":"password"} value={password}
                    onChange={e=>setPassword(e.target.value)}
                    placeholder={mode==="signup"?"Create a password (8+ chars)":"Password"}
                    style={{...iStyle,paddingRight:56}}
                    onFocus={e=>e.target.style.borderColor="rgba(240,180,41,0.4)"}
                    onBlur={e=>e.target.style.borderColor=G.inpBorder}
                    onKeyDown={e=>{if(e.key==="Enter") mode==="signup"?handleSignup():handleLogin();}}/>
                  <button onClick={()=>setShowPass(p=>!p)}
                    style={{position:"absolute",right:14,top:"50%",transform:"translateY(-50%)",
                      background:"none",border:"none",color:G.dimmer,cursor:"pointer",fontSize:12,padding:0}}>
                    {showPass?"Hide":"Show"}
                  </button>
                </div>

                {error&&<p style={{color:"#e05252",fontSize:13,margin:"4px 0 10px",lineHeight:1.5}}>{error}</p>}

                <button onClick={mode==="signup"?handleSignup:handleLogin} disabled={loading}
                  style={{width:"100%",padding:"15px",background:G.gold,color:"#000",border:"none",
                    borderRadius:12,fontSize:15,fontWeight:700,cursor:"pointer",marginBottom:14,
                    opacity:loading?.7:1,boxShadow:"0 0 30px rgba(240,180,41,0.15)"}}>
                  {loading?"Please wait…":mode==="signup"?"Create Account →":"Sign In →"}
                </button>

                {mode==="login"&&(
                  <button onClick={()=>setMode("forgot")}
                    style={{background:"none",border:"none",color:G.dimmer,cursor:"pointer",
                      fontSize:12,display:"block",textAlign:"center",width:"100%",marginBottom:6}}>
                    Forgot your password?
                  </button>
                )}
              </>
            )}

            {/* Toggle login / signup */}
            <div style={{textAlign:"center",fontSize:13,color:G.dimmer}}>
              {mode==="signup"?(
                <>Already have an account?{" "}
                <button onClick={()=>{setMode("login");setTab("");setError("");}}
                  style={{background:"none",border:"none",color:G.gold,cursor:"pointer",fontSize:13,fontWeight:600,padding:0}}>
                  Sign in
                </button></>
              ):(
                <>Don't have an account?{" "}
                <button onClick={()=>{setMode("signup");setTab("email");setError("");}}
                  style={{background:"none",border:"none",color:G.gold,cursor:"pointer",fontSize:13,fontWeight:600,padding:0}}>
                  Create one free
                </button></>
              )}
            </div>
          </div>
        )}

        {/* Terms */}
        {(mode==="login"||mode==="signup")&&(
          <p style={{textAlign:"center",fontSize:11,color:G.dimmer,margin:"18px 0 0",lineHeight:1.6}}>
            By continuing, you agree to our{" "}
            <span style={{color:G.gold,cursor:"pointer"}} onClick={()=>window.dispatchEvent(new CustomEvent("showPolicy",{detail:"terms"}))}>Terms of Service</span>{" "}and{" "}
            <span style={{color:G.gold,cursor:"pointer"}} onClick={()=>window.dispatchEvent(new CustomEvent("showPolicy",{detail:"privacy"}))}>Privacy Policy</span>
          </p>
        )}
        {/* Build stamp — verifies which code version the device is running */}
        <div style={{textAlign:"center",fontSize:9,color:G.dimmer,opacity:0.5,marginTop:10,fontFamily:"monospace"}}>
          v-oauth-pkce-2
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// RELOCATION EXPLORER — Clean rebuild
// User picks or types a country → AI generates a full personalised report
// ═══════════════════════════════════════════════════════════════════════════════
const RELOC_COUNTRIES = [
  "Canada","United Kingdom","Germany","Australia","Netherlands","Portugal","Spain",
  "United Arab Emirates","Singapore","New Zealand","Ireland","Sweden","Norway",
  "Denmark","Switzerland","Austria","Belgium","Finland","Japan","South Korea",
  "United States","France","Italy","Czech Republic","Poland","Hungary","Romania",
  "Estonia","Latvia","Lithuania","Malta","Cyprus","Greece","Croatia",
  "Malaysia","Thailand","Vietnam","Indonesia","Philippines","India","Mexico",
  "Brazil","Argentina","Colombia","Chile","Costa Rica","Panama","South Africa",
  "Kenya","Ghana","Rwanda","Mauritius","Tanzania","Ethiopia","Senegal","Morocco",
  "Egypt","Tunisia","Nigeria","Uganda","Zambia","Zimbabwe","Botswana","Namibia",
  "Saudi Arabia","Qatar","Bahrain","Kuwait","Oman","Jordan","Lebanon","Turkey",
  "Georgia","Armenia","Azerbaijan","Kazakhstan","Ukraine","Serbia","Montenegro",
  "Sri Lanka","Nepal","Bangladesh","China","Taiwan","Hong Kong",
  "Cambodia","Myanmar","Laos","Papua New Guinea","Fiji",
  "Cuba","Jamaica","Trinidad and Tobago","Dominican Republic",
  "Guatemala","Honduras","El Salvador","Peru","Ecuador","Bolivia","Uruguay",
];

function RelocationExplorer({formData, userId, isPremium, isPaid, onUnlock}){
  const G = useThemeColors();
  const [query, setQuery]     = useState("");
  const [report, setReport]   = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState("");
  const [openSection, setOpenSection]     = useState(null);
  const [sectionData, setSectionData]     = useState({});
  const [sectionBusy, setSectionBusy]     = useState({});

  const name   = formData?.name    || "you";
  const from   = formData?.country || "your country";
  const skills = formData?.skills  || formData?.career || "your skills";
  const goals  = formData?.goals   || formData?.bigGoal || "improve your life";
  const income = formData?.income  || "not specified";
  const age    = formData?.age     || "unknown";

  const suggestions = query.trim().length > 0
    ? RELOC_COUNTRIES.filter(c =>
        c.toLowerCase().includes(query.toLowerCase()) &&
        c.toLowerCase() !== (from || "").toLowerCase()
      ).slice(0, 7)
    : [];

  const runReport = async (country) => {
    if (!isPaid) { onUnlock && onUnlock(); return; }
    setQuery(country);
    setReport(null);
    setError("");
    setSectionData({});
    setOpenSection(null);
    setLoading(true);
    try {
      const prompt = `Give ${name} (age ${age}, from ${from}, skills: ${skills}, goal: ${goals}, income: ${income}) a relocation intelligence report for ${country}.
Return ONLY valid JSON, no markdown, no code fences. Start { end }:
{"country":"${country}","fit":<0-100>,"tagline":"<one punchy sentence for them>","overview":"<2 sentences about ${country} from a ${from} perspective>","pros":["<pro1>","<pro2>","<pro3>"],"cons":["<con1>","<con2>","<con3>"],"living":"<monthly costs in ${country} local currency + USD equivalent>","visa":"<easy|moderate|hard>","visa_detail":"<specific visa pathway for someone from ${from}>","opportunity":<0-100>,"cost":"<low|medium|high>","verdict":"<2 honest sentences: should they go and why>"}`;
      const raw = await callAPI({
        messages:[{role:"user",content:prompt}],
        system:"You are a relocation intelligence advisor. Return ONLY valid JSON. No markdown. Be specific with real numbers and real visa names.",
        userId, isPremium,
      });
      const txt = typeof raw==="string" ? raw :
        (raw?.content?.filter(x=>x?.type==="text").map(x=>x.text).join("")||raw?.text||"");
      const clean = txt.replace(/```json|```/g,"").trim();
      const s=clean.indexOf("{"), e=clean.lastIndexOf("}");
      if(s===-1||e===-1) throw new Error("No JSON");
      const parsed = JSON.parse(clean.slice(s,e+1));
      setReport(parsed);
    } catch(err) {
      setError("Could not generate report. Tap Try Again.");
    }
    setLoading(false);
  };

  const runSection = async (key, prompt) => {
    if (!isPaid) { onUnlock && onUnlock(); return; }
    setSectionBusy(p=>({...p,[key]:true}));
    try {
      const raw = await callAPI({
        messages:[{role:"user",content:prompt}],
        system:`You are a relocation advisor. Write for ${name} from ${from} moving to ${report?.country}. Be specific, practical, real numbers. Max 280 words.`,
        userId, isPremium,
      });
      const txt = typeof raw==="string" ? raw :
        (raw?.content?.filter(x=>x?.type==="text").map(x=>x.text).join("")||raw?.text||"");
      setSectionData(p=>({...p,[key]:txt}));
    } catch {
      setSectionData(p=>({...p,[key]:"Could not generate. Tap again to retry."}));
    }
    setSectionBusy(p=>({...p,[key]:false}));
  };

  const fitColor = !report ? G.gold
    : report.fit>=70 ? "#81c784"
    : report.fit>=40 ? "#f0b429" : "#e05c6e";

  const SECTIONS = !report ? [] : [
    {key:"visa_steps",  icon:"🛂", title:"Step-by-Step Visa Guide",
     prompt:`Write a step-by-step visa guide for ${name} from ${from} to move to ${report.country}. Specific visa name, documents needed, where to apply, fees in local currency + USD, processing time, and what to do if rejected.`},
    {key:"jobs",        icon:"💼", title:"Jobs & Income Potential",
     prompt:`Analyse the job market in ${report.country} for ${name} with skills: ${skills} and income: ${income}. In-demand roles for their skills, salary range in local currency + USD, top hiring platforms, remote work viability, and the #1 skill to add to be competitive there.`},
    {key:"costs",       icon:"💰", title:"Full Cost of Living Breakdown",
     prompt:`Give ${name} a detailed monthly cost of living in ${report.country}: rent (1-bed and 2-bed in a good neighbourhood), groceries, transport, utilities, phone, healthcare, entertainment. All in local currency + USD. Total it up and compare to their income of ${income}.`},
    {key:"plan",        icon:"🚀", title:"First 90 Days Action Plan",
     prompt:`Write a month-by-month plan for ${name}'s first 90 days after arriving in ${report.country}. Month 1: admin and settling in. Month 2: building income/employment. Month 3: establishing life. What to do, where to go, what it costs, what success looks like.`},
    {key:"culture",     icon:"🌍", title:"Culture & Community",
     prompt:`Explain living in ${report.country} for someone from ${from}: cultural differences to expect, how locals treat immigrants, communities from ${from} that exist there, language situation, social life, and the honest truth about whether people from ${from} feel welcome and happy there.`},
  ];

  return (
    <div style={{minHeight:"100vh",background:G.bg,color:G.cream,
      fontFamily:"-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif",paddingBottom:100}}>

      {/* ── HEADER ── */}
      <div style={{padding:"20px 20px 0",maxWidth:860,margin:"0 auto"}}>
        <div style={{marginBottom:20}}>
          <div style={{fontSize:10,fontWeight:700,letterSpacing:".15em",color:G.gold,
            fontFamily:"monospace",marginBottom:6}}>RELOCATION INTELLIGENCE</div>
          <h2 style={{fontSize:"clamp(18px,5vw,24px)",fontWeight:800,color:G.cream,margin:"0 0 6px"}}>
            Where in the world should you go?
          </h2>
          <p style={{fontSize:13,color:G.dim,margin:0,lineHeight:1.6}}>
            Type any country and get a full AI relocation report — visa, cost of living, jobs, and a 90-day action plan.
          </p>
        </div>

        {/* ── SEARCH ── */}
        <div style={{position:"relative",marginBottom:16}}>
          <input value={query} onChange={e=>{setQuery(e.target.value);setReport(null);setError("");}}
            placeholder="Type a country name…"
            style={{width:"100%",padding:"14px 48px 14px 18px",
              background:G.card,border:"1px solid "+(query?G.gold+"60":G.border),
              borderRadius:14,color:G.cream,fontSize:15,fontFamily:"inherit",
              outline:"none",boxSizing:"border-box",transition:"border-color .2s"}}
          />
          {query&&(
            <button onClick={()=>{setQuery("");setReport(null);setError("");}}
              style={{position:"absolute",right:14,top:"50%",transform:"translateY(-50%)",
                background:"none",border:"none",color:G.dimmer,cursor:"pointer",fontSize:20,padding:0}}>
              ×
            </button>
          )}
          {/* Dropdown */}
          {suggestions.length>0&&!report&&!loading&&(
            <div style={{position:"absolute",top:"calc(100% + 6px)",left:0,right:0,zIndex:200,
              background:G.card,border:"1px solid "+G.border,borderRadius:14,
              overflow:"hidden",boxShadow:"0 8px 32px rgba(0,0,0,0.35)"}}>
              {suggestions.map(c=>(
                <div key={c} onClick={()=>runReport(c)}
                  style={{padding:"13px 18px",cursor:"pointer",fontSize:14,color:G.cream,
                    borderBottom:"1px solid "+G.border,display:"flex",alignItems:"center",gap:10,
                    transition:"background .12s"}}
                  onMouseEnter={e=>e.currentTarget.style.background=G.gold+"15"}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <span style={{fontSize:16}}>🌍</span>
                  <span>{c}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Quick picks */}
        {!report&&!loading&&(
          <div style={{marginBottom:28}}>
            <div style={{fontSize:10,fontWeight:700,letterSpacing:".1em",color:G.dimmer,
              fontFamily:"monospace",marginBottom:10}}>POPULAR DESTINATIONS</div>
            <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
              {["Canada","UK","Germany","Australia","UAE","Portugal","Singapore","Ghana"].map(c=>(
                <button key={c} onClick={()=>runReport(c==="UK"?"United Kingdom":c)}
                  style={{padding:"7px 14px",borderRadius:20,fontSize:12,fontWeight:600,
                    border:"1px solid "+G.border,background:"rgba(255,255,255,0.03)",
                    color:G.dim,cursor:"pointer",fontFamily:"inherit",transition:"all .15s"}}
                  onMouseEnter={e=>{e.currentTarget.style.borderColor=G.gold+"60";e.currentTarget.style.color=G.cream;}}
                  onMouseLeave={e=>{e.currentTarget.style.borderColor=G.border;e.currentTarget.style.color=G.dim;}}>
                  {c}
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* ── LOADING ── */}
      {loading&&(
        <div style={{textAlign:"center",padding:"64px 20px"}}>
          <div style={{fontSize:44,marginBottom:16}}>🌍</div>
          <div style={{fontSize:15,color:G.dim,marginBottom:6}}>Analysing {query} for you…</div>
          <div style={{fontSize:12,color:G.dimmer}}>Checking visas, cost of living, job market and more</div>
        </div>
      )}

      {/* ── ERROR ── */}
      {error&&!loading&&(
        <div style={{margin:"0 20px 20px",padding:"16px 20px",
          background:"rgba(224,92,110,0.08)",border:"1px solid rgba(224,92,110,0.25)",
          borderRadius:14,textAlign:"center"}}>
          <div style={{fontSize:13,color:"#e05c6e",marginBottom:10}}>{error}</div>
          <button onClick={()=>query&&runReport(query)}
            style={{background:G.gold,border:"none",borderRadius:10,padding:"10px 22px",
              fontSize:13,fontWeight:700,color:"#000",cursor:"pointer",fontFamily:"inherit"}}>
            Try Again
          </button>
        </div>
      )}

      {/* ── REPORT ── */}
      {report&&!loading&&(
        <div style={{padding:"0 20px",maxWidth:860,margin:"0 auto"}}>

          {/* Hero */}
          <div style={{background:G.card,border:"1px solid "+fitColor+"40",
            borderRadius:20,padding:"24px",marginBottom:14,position:"relative",overflow:"hidden"}}>
            <div style={{position:"absolute",top:0,left:0,right:0,height:3,
              background:`linear-gradient(90deg,${fitColor},${fitColor}60)`,borderRadius:"20px 20px 0 0"}}/>
            <div style={{display:"flex",alignItems:"flex-start",gap:16,marginBottom:16}}>
              <div style={{fontSize:40,flexShrink:0}}>🌍</div>
              <div style={{flex:1}}>
                <h3 style={{fontSize:"clamp(18px,5vw,24px)",fontWeight:900,color:G.cream,margin:"0 0 4px"}}>
                  {report.country}
                </h3>
                <p style={{fontSize:13,color:G.dim,margin:0,lineHeight:1.6}}>{report.tagline}</p>
              </div>
              <div style={{textAlign:"center",flexShrink:0}}>
                <div style={{fontSize:26,fontWeight:900,color:fitColor,lineHeight:1}}>{report.fit}</div>
                <div style={{fontSize:9,color:G.dimmer,fontFamily:"monospace",letterSpacing:".06em"}}>FIT SCORE</div>
              </div>
            </div>
            {/* Stats row */}
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:14}}>
              {[
                {label:"VISA",        val:report.visa,        col:report.visa==="easy"?"#81c784":report.visa==="moderate"?"#f0b429":"#e05c6e"},
                {label:"COST",        val:report.cost,        col:report.cost==="low"?"#81c784":report.cost==="medium"?"#f0b429":"#e05c6e"},
                {label:"OPPORTUNITY", val:report.opportunity+"/100", col:G.gold},
              ].map(s=>(
                <div key={s.label} style={{background:"rgba(255,255,255,0.03)",
                  border:"1px solid "+G.border,borderRadius:10,padding:"10px 8px",textAlign:"center"}}>
                  <div style={{fontSize:8,color:G.dimmer,fontFamily:"monospace",letterSpacing:".08em",marginBottom:3}}>{s.label}</div>
                  <div style={{fontSize:13,fontWeight:800,color:s.col,textTransform:"capitalize"}}>{s.val}</div>
                </div>
              ))}
            </div>
            <p style={{fontSize:13,color:G.dim,lineHeight:1.8,margin:0}}>{report.overview}</p>
          </div>

          {/* Pros & Cons */}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>
            {[
              {label:"ADVANTAGES",col:"#81c784",items:report.pros||[],tick:"✓"},
              {label:"CHALLENGES",col:"#e05c6e",items:report.cons||[],tick:"•"},
            ].map(side=>(
              <div key={side.label} style={{background:G.card,
                border:`1px solid ${side.col}25`,borderRadius:14,padding:"14px"}}>
                <div style={{fontSize:9,fontWeight:700,letterSpacing:".1em",color:side.col,
                  fontFamily:"monospace",marginBottom:10}}>{side.label}</div>
                {side.items.map((item,i)=>(
                  <div key={i} style={{display:"flex",gap:8,marginBottom:7}}>
                    <span style={{color:side.col,flexShrink:0,fontSize:12}}>{side.tick}</span>
                    <span style={{fontSize:12,color:G.dim,lineHeight:1.6}}>{item}</span>
                  </div>
                ))}
              </div>
            ))}
          </div>

          {/* Cost / Visa / Verdict */}
          {[
            {icon:"💰",label:"COST OF LIVING",    val:report.living},
            {icon:"🛂",label:"VISA OVERVIEW",     val:report.visa_detail},
            {icon:"✦", label:"VERDICT",           val:report.verdict},
          ].map(row=>(
            <div key={row.label} style={{background:G.card,border:"1px solid "+G.border,
              borderRadius:14,padding:"14px 16px",marginBottom:10}}>
              <div style={{fontSize:9,fontWeight:700,letterSpacing:".1em",color:G.gold,
                fontFamily:"monospace",marginBottom:7}}>{row.icon} {row.label}</div>
              <div style={{fontSize:13,color:G.dim,lineHeight:1.75}}>{row.val}</div>
            </div>
          ))}

          {/* Deep dive collapsible sections */}
          <div style={{marginBottom:20}}>
            <div style={{fontSize:9,fontWeight:700,letterSpacing:".1em",color:G.dimmer,
              fontFamily:"monospace",marginBottom:4}}>DEEP INTELLIGENCE</div>
            <p style={{fontSize:12,color:G.dimmer,margin:"0 0 12px",lineHeight:1.5}}>
              Tap any section for a full personalised breakdown.
            </p>
            {SECTIONS.map(sec=>{
              const isOpen = openSection===sec.key;
              const busy   = sectionBusy[sec.key];
              const data   = sectionData[sec.key];
              return(
                <div key={sec.key} style={{background:G.card,
                  border:"1px solid "+(isOpen?G.gold+"40":G.border),
                  borderRadius:14,overflow:"hidden",marginBottom:8,transition:"border-color .2s"}}>
                  <div onClick={()=>{
                    if(isOpen){setOpenSection(null);return;}
                    setOpenSection(sec.key);
                    if(!data&&!busy) runSection(sec.key,sec.prompt);
                  }}
                    style={{padding:"13px 16px",cursor:"pointer",display:"flex",
                      alignItems:"center",gap:12,
                      background:isOpen?G.gold+"08":"transparent"}}>
                    <span style={{fontSize:17,flexShrink:0}}>{sec.icon}</span>
                    <div style={{flex:1,fontSize:14,fontWeight:700,color:G.cream}}>{sec.title}</div>
                    <span style={{color:isOpen?G.gold:G.dimmer,fontSize:17,
                      display:"inline-block",transition:"transform .2s",
                      transform:isOpen?"rotate(90deg)":"rotate(0deg)"}}>›</span>
                  </div>
                  {isOpen&&(
                    <div style={{padding:"12px 16px 14px",borderTop:"1px solid "+G.border}}>
                      {busy?(
                        <div style={{display:"flex",alignItems:"center",gap:8,padding:"8px 0"}}>
                          <span style={{width:6,height:6,borderRadius:"50%",background:G.gold,display:"inline-block"}}/>
                          <div style={{fontSize:12,color:G.dimmer}}>Generating…</div>
                        </div>
                      ):data?(
                        <div>
                          <div style={{fontSize:13,color:G.dim,lineHeight:1.85,
                            whiteSpace:"pre-wrap",marginBottom:10}}>{data}</div>
                          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                            <button onClick={()=>runSection(sec.key,sec.prompt)}
                              style={{background:"none",border:"1px solid "+G.border,borderRadius:8,
                                padding:"6px 14px",fontSize:11,color:G.dimmer,
                                cursor:"pointer",fontFamily:"inherit"}}>↺ Refresh</button>
                            <button onClick={()=>{
                              addProgressPoints(userId,`reloc_${sec.key}_${report?.country}_${new Date().toISOString().slice(0,10)}`,PROGRESS_POINTS.deepdive_done);
                              window.dispatchEvent(new CustomEvent("showToast",{detail:"✓ Marked as done — progress updated!"}));
                            }}
                              style={{background:G.gold+"18",border:"1px solid "+G.gold+"40",
                                borderRadius:8,padding:"6px 14px",fontSize:11,color:G.gold,
                                fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>
                              ✓ I've read this
                            </button>
                          </div>
                        </div>
                      ):(
                        <div style={{textAlign:"center",padding:"10px 0"}}>
                          <button onClick={()=>runSection(sec.key,sec.prompt)}
                            style={{background:G.gold,color:"#000",border:"none",borderRadius:10,
                              padding:"11px 22px",fontSize:13,fontWeight:700,
                              cursor:"pointer",fontFamily:"inherit"}}>
                            ✦ Generate {sec.title}
                          </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {/* Try another */}
          <button onClick={()=>{setReport(null);setQuery("");setError("");setSectionData({});setOpenSection(null);}}
            style={{width:"100%",padding:"13px",background:"rgba(255,255,255,0.04)",
              border:"1px solid "+G.border,borderRadius:14,color:G.dim,
              fontSize:14,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>
            🌍 Explore Another Country
          </button>
        </div>
      )}
    </div>
  );
}


